import { useState, useEffect, useCallback } from 'react';
import { Wind, Search } from 'lucide-react';
import './App.css';

// Component imports
import CurrentAQI from './components/CurrentAQI';
import MainPollutant from './components/MainPollutant';
import AQITrendGraph from './components/AQITrendGraph';
import PredictionPanel from './components/PredictionPanel';
import PollutantAnalysis from './components/PollutantAnalysis';
import AlertSystem from './components/AlertSystem';
import WeeklyForecast from './components/WeeklyForecast';
import LandingPage from './components/LandingPage';
import Navbar from './components/Navbar';
import PredictionsPage from './components/PredictionsPage';
import HealthAdvisory from './components/HealthAdvisory';
import PollutantsPage from './components/PollutantsPage';
import HistoryPage from './components/HistoryPage';
import { fetchAQIData, fetchPredictedAQI } from './services/api';


function App() {
  const [showDashboard, setShowDashboard] = useState(false);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [searchInput, setSearchInput] = useState("");
  const [searchQuery, setSearchQuery] = useState("pune");

  const [historicalCache, setHistoricalCache] = useState({});
  const [yearlyCache, setYearlyCache] = useState({});

  const handleHistoryUpdate = (city, data, stationInfo) => {
    setHistoricalCache(prev => ({ ...prev, [city]: { data, stationInfo } }));
  };

  const handleYearlyUpdate = (city, data, cities) => {
    setYearlyCache(prev => ({ ...prev, [city]: { data, cities } }));
  };

  const [aqiData, setAqiData] = useState({
    currentAQI: 0,
    status: 'Loading...',
    pollutants: { PM25: 0, PM10: 0, NO2: 0, SO2: 0, CO: 0, O3: 0 },
    cityName: 'Loading...'
  });

  const [isLoading, setIsLoading] = useState(true);

  const getAQIData = useCallback(async () => {
    setIsLoading(true);
    const data = await fetchAQIData(searchQuery);
    if (data) {
      setAqiData(data);
    }
    setIsLoading(false);
  }, [searchQuery]);


  useEffect(() => {
    if (showDashboard) {
      getAQIData();

      // refresh every 5 minutes
      const interval = setInterval(getAQIData, 5 * 60 * 1000);

      return () => clearInterval(interval);
    }
  }, [showDashboard, getAQIData]);

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchInput.trim()) {
      setSearchQuery(searchInput.trim());
    }
  };

  if (!showDashboard) {
    return <LandingPage onGetStarted={() => setShowDashboard(true)} />;
  }

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500"></div>
      </div>
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'predictions':
        return <PredictionsPage />;
      case 'history':
        return (
          <HistoryPage 
            city={searchQuery} 
            liveData={aqiData}
            cache={historicalCache[searchQuery]}
            yearlyCache={yearlyCache}
            onHistoryUpdate={(data, info) => handleHistoryUpdate(searchQuery, data, info)}
            onYearlyUpdate={handleYearlyUpdate}
          />
        );
      case 'health':
        return <HealthAdvisory />;
      case 'pollutants':
        return <PollutantsPage data={aqiData} />;
      case 'dashboard':
      default:
        return (
          <main
            className="grid grid-cols-1 lg:grid-cols-3 gap-6 animate-slide-up"
            style={{ animationDelay: '0.2s' }}
          >
            {/* Top Section - AQI Overview & Main Pollutant Grid */}
            <div className="lg:col-span-3 grid grid-cols-1 md:grid-cols-2 gap-6 max-w-4xl mx-auto w-full">
              <CurrentAQI data={aqiData} />
              <MainPollutant data={aqiData} />
            </div>

            {/* Health Status / Alert Section - Centered */}

            <div className="lg:col-span-3 flex justify-center">
              <AlertSystem aqi={aqiData.currentAQI} />
            </div>
          </main>
        );
    }
  };

  return (
    <div className="max-w-[1400px] mx-auto px-6 py-8">
      <Navbar
        onSearch={handleSearch}
        searchInput={searchInput}
        setSearchInput={setSearchInput}
        onBackToHome={() => setShowDashboard(false)}
        activeTab={activeTab}
        setActiveTab={setActiveTab}
      />

      {renderContent()}
    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from 'recharts';

// Generate DATE-WISE data for the trend graph
const generateDatewiseData = () => {
  const data = [];
  let baseAQI = 60;

  // Generate data for the last 7 days
  for (let i = 7; i >= 0; i--) {
    const date = new Date();
    date.setDate(date.getDate() - i);

    // Add some random walk for daily averages
    baseAQI += Math.floor(Math.random() * 25) - 12;
    baseAQI = Math.max(20, Math.min(250, baseAQI)); // clamp between 20 and 250

    data.push({
      // Use just month and day (e.g. "Oct 12")
      date: date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
      aqi: baseAQI,
    });
  }
  return data;
};

const CustomTooltip = ({ active, payload, label }) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-white/90 backdrop-blur-md border border-slate-200 p-3 rounded-xl shadow-lg">
        <p className="text-slate-500 text-xs mb-1 font-medium">{label}</p>
        <p className="text-blue-600 font-bold m-0">
          Daily Avg AQI: <span className="text-slate-800">{payload[0].value}</span>
        </p>
      </div>
    );
  }
  return null;
};

const AQITrendGraph = () => {
  const [data, setData] = useState([]);

  useEffect(() => {
    setData(generateDatewiseData());
  }, []);

  return (
    <div className="glass-panel lg:col-span-2 col-span-1 border border-slate-200 bg-white">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-xl font-semibold text-slate-800 m-0">AQI Trend (Last 7 Days)</h2>
        <span className="bg-blue-50 text-blue-600 px-3 py-1 rounded-full text-xs font-bold tracking-wider">HISTORICAL</span>
      </div>

      <div className="w-full h-[300px]">
        <ResponsiveContainer width="100%" height="100%">
          <AreaChart
            data={data}
            margin={{ top: 10, right: 10, left: -20, bottom: 0 }}
          >
            <defs>
              <linearGradient id="colorAqiLight" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.4} />
                <stop offset="95%" stopColor="#3b82f6" stopOpacity={0.0} />
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" vertical={false} />
            <XAxis
              dataKey="date"
              stroke="#64748b"
              tick={{ fill: '#64748b', fontSize: 12 }}
              tickLine={false}
              axisLine={false}
              minTickGap={40} // Avoid overlapping dates
            />
            <YAxis
              stroke="#64748b"
              tick={{ fill: '#64748b', fontSize: 12 }}
              tickLine={false}
              axisLine={false}
            />
            <Tooltip content={<CustomTooltip />} />
            <Area
              type="monotone"
              dataKey="aqi"
              stroke="#3b82f6"
              strokeWidth={3}
              fillOpacity={1}
              fill="url(#colorAqiLight)"
              animationDuration={1500}
            />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export default AQITrendGraph;

import React, { useState, useEffect } from 'react';
import {
  Wind, Factory, Car, FlaskConical, Thermometer,
  ShieldAlert, Info, TrendingUp, TrendingDown, Minus
} from 'lucide-react';
import {
  AreaChart, Area, ResponsiveContainer, YAxis, Tooltip, XAxis
} from 'recharts';
import { fetchHistoricalAQI } from '../services/api';

const PollutantTrendCard = ({ item, city, liveValue }) => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [trend, setTrend] = useState('stable'); // up, down, stable

  useEffect(() => {
    const loadHistory = async () => {
      setLoading(true);
      try {
        const paramMap = {
          'PM2.5': 'pm25',
          'PM10': 'pm10',
          'O3': 'o3',
          'NO2': 'no2',
          'SO2': 'so2',
          'CO': 'co'
        };
        const res = await fetchHistoricalAQI(city, paramMap[item.name] || 'pm25');
        if (res && res.data) {
          setHistory(res.data);

          // Calculate trend
          if (res.data.length > 2) {
            const last = res.data[res.data.length - 1].aqi;
            const prev = res.data[res.data.length - 2].aqi;
            if (last > prev + 5) setTrend('up');
            else if (last < prev - 5) setTrend('down');
            else setTrend('stable');
          }
        }
      } catch (err) {
        console.error(`Error loading history for ${item.name}:`, err);
      } finally {
        setLoading(false);
      }
    };

    if (city) loadHistory();
  }, [city, item.name]);

  return (
    <div className={`glass-panel bg-white border-slate-200 p-6 transition-all duration-300 hover:shadow-2xl flex flex-col group relative overflow-hidden mb-6`}>
      {/* Light Hover Shade Background */}
      <div className={`absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-300 pointer-events-none ${item.color.replace('/50', '/20')}`} />

      <div className="flex items-center justify-between mb-2 relative z-10">
        <div className="flex items-center gap-4">
          <div className={`p-3 bg-white rounded-xl shadow-sm border border-slate-100 group-hover:scale-110 transition-transform`}>
            {React.cloneElement(item.icon, { size: 28 })}
          </div>
          <div>
            <h2 className="text-2xl font-bold text-slate-800 m-0">{item.name}</h2>
            <div className="text-slate-500 font-bold text-[10px] tracking-wider uppercase">{item.fullName}</div>
          </div>
        </div>
        <div className="text-right flex items-center gap-6">
          <div className="text-right">
            <div className="text-[10px] text-slate-400 font-bold uppercase mb-1">Current</div>
            <div className="flex items-center gap-2 justify-end">
              <span className="text-3xl font-black text-slate-800 font-mono">{liveValue}</span>
              <span className="text-sm text-slate-500 font-bold">{item.unit}</span>
            </div>
          </div>
          <div className="h-12 w-px bg-slate-200 hidden md:block"></div>
          <div className="hidden md:flex flex-col items-end justify-center w-24">
            <div className="text-[10px] text-slate-400 font-bold uppercase mb-1">Trend</div>
            <div className="flex items-center gap-1">
              {trend === 'up' && <><TrendingUp size={18} className="text-rose-500" /><span className="text-sm font-bold text-rose-500">Rising</span></>}
              {trend === 'down' && <><TrendingDown size={18} className="text-emerald-500" /><span className="text-sm font-bold text-emerald-500">Falling</span></>}
              {trend === 'stable' && <><Minus size={18} className="text-slate-400" /><span className="text-sm font-bold text-slate-400">Stable</span></>}
            </div>
          </div>
        </div>
      </div>

      {/* Main Trend Graph */}
      <div className="h-48 w-full mt-4 relative z-10 rounded-xl overflow-hidden border border-slate-100 bg-slate-50/50 p-2">
        {loading ? (
          <div className="w-full h-full flex items-center justify-center">
            <div className="flex flex-col items-center gap-3">
              <div className="w-6 h-6 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" />
              <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Loading History</span>
            </div>
          </div>
        ) : (
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={history} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
              <defs>
                <linearGradient id={`color-${item.name}`} x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor={item.hexColor} stopOpacity={0.4} />
                  <stop offset="95%" stopColor={item.hexColor} stopOpacity={0} />
                </linearGradient>
              </defs>
              <XAxis
                dataKey="date"
                axisLine={false}
                tickLine={false}
                tick={{ fontSize: 10, fill: '#94a3b8' }}
                dy={5}
                minTickGap={30}
              />
              <YAxis
                axisLine={false}
                tickLine={false}
                tick={{ fontSize: 10, fill: '#94a3b8' }}
              />
              <Tooltip
                cursor={{ stroke: '#cbd5e1', strokeWidth: 1, strokeDasharray: '4 4' }}
                content={({ active, payload }) => {
                  if (active && payload && payload.length) {
                    return (
                      <div className="bg-slate-800 backdrop-blur-md border border-slate-700 p-3 rounded-xl shadow-2xl text-white">
                        <p className="font-bold text-lg m-0 flex items-center gap-2">
                          {payload[0].value} <span className="text-xs text-slate-400 font-normal">{item.unit}</span>
                        </p>
                        <p className="text-slate-300 text-xs m-0 mt-1">{payload[0].payload.date}</p>
                      </div>
                    );
                  }
                  return null;
                }}
              />
              <Area
                type="monotone"
                dataKey="aqi"
                stroke={item.hexColor}
                strokeWidth={3}
                fillOpacity={1}
                fill={`url(#color-${item.name})`}
                animationDuration={1500}
              />
            </AreaChart>
          </ResponsiveContainer>
        )}
      </div>
    </div>
  );
};

const PollutantsPage = ({ data }) => {
  const currentCity = data?.cityName || 'Pune';

  const pollutants = [
    {
      name: 'PM2.5',
      fullName: 'Particulate Matter < 2.5µm',
      icon: <Wind className="text-blue-500" />,
      unit: 'µg/m³',
      hexColor: '#3b82f6',
      description: 'Fine particles that can penetrate deep into lungs and bloodstream.',
      color: 'bg-blue-50/50',
    },
    {
      name: 'PM10',
      fullName: 'Particulate Matter < 10µm',
      icon: <Wind className="text-cyan-500" />,
      unit: 'µg/m³',
      hexColor: '#06b6d4',
      description: 'Coarser particles that can irritate eyes, nose, and throat.',
      color: 'bg-cyan-50/50',
    },
    {
      name: 'O3',
      fullName: 'Ground-level Ozone',
      icon: <Thermometer className="text-orange-500" />,
      unit: 'ppb',
      hexColor: '#f97316',
      description: 'Created by chemical reactions between NOx and VOC in sunlight.',
      color: 'bg-orange-50/50',
    },
    {
      name: 'NO2',
      fullName: 'Nitrogen Dioxide',
      icon: <Car className="text-red-500" />,
      unit: 'ppb',
      hexColor: '#ef4444',
      description: 'Highly reactive gas primarily formed through fuel burning.',
      color: 'bg-red-50/50',
    },
    {
      name: 'CO',
      fullName: 'Carbon Monoxide',
      icon: <Factory className="text-slate-500" />,
      unit: 'ppm',
      hexColor: '#64748b',
      description: 'Odorless, colorless gas harmful when inhaled in large amounts.',
      color: 'bg-slate-50/50',
    },
    {
      name: 'SO2',
      fullName: 'Sulfur Dioxide',
      icon: <FlaskConical className="text-purple-500" />,
      unit: 'ppb',
      hexColor: '#8b5cf6',
      description: 'Pungent gas released by burning fossil fuels containing sulfur.',
      color: 'bg-purple-50/50',
    }
  ];

  return (
    <div className="animate-slide-up pb-12">
      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-4">
          <div className="p-3 bg-blue-500 text-white rounded-2xl shadow-lg shadow-blue-100">
            <Wind size={32} />
          </div>
          <div>
            <h1 className="text-4xl font-bold text-slate-800 m-0">Pollutant Trends</h1>
            <p className="text-slate-500 font-medium">Real-time concentrations and 7-day movement for {currentCity}.</p>
          </div>
        </div>
      </div>

      <div className="flex flex-col max-w-5xl mx-auto">
        {pollutants
          .map(p => ({
            ...p,
            liveValue: data?.pollutants?.[p.name.replace('.', '')] ?? 'N/A'
          }))
          .filter(p => p.liveValue !== 'N/A' && p.liveValue !== null) // Filter out unavailable pollutants
          .map((p, idx) => (
            <PollutantTrendCard
              key={idx}
              item={p}
              city={currentCity}
              liveValue={p.liveValue}
            />
          ))}

        {/* Empty State Fallback */}
        {pollutants.filter(p => (data?.pollutants?.[p.name.replace('.', '')] ?? 'N/A') !== 'N/A').length === 0 && (
          <div className="p-12 text-center bg-slate-50 rounded-2xl border border-slate-200 border-dashed">
            <h3 className="text-xl font-bold text-slate-600 mb-2">No Pollutant Data Available</h3>
            <p className="text-slate-500">The current monitoring station is not reporting individual pollutant breakdowns.</p>
          </div>
        )}
      </div>

    </div>
  );
};

export default PollutantsPage;

export default PollutantsPage;
